import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const ModeratorDashboard = () => {
  const [users, setUsers] = useState([]);
  const [error, setError] = useState('');
  const [editingUser, setEditingUser] = useState(null);
  const [editedData, setEditedData] = useState({ username: '', role: '' });
  const [showForm, setShowForm] = useState(false);
  const [newUser, setNewUser] = useState({
    username: '',
    email: '',
    password: '',
    role: 'student',
  });

  const navigate = useNavigate();
  const token = localStorage.getItem('accessToken');

  useEffect(() => {
    if (!token) {
      setError('No token found. Please log in again.');
      navigate('/login');
      return;
    }

    fetch('http://localhost:8000/api/manage-users/', {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) {
          setUsers(data);
        } else {
          setError('Invalid response format');
          console.log('API response:', data);
        }
      })
      .catch(err => {
        console.error(err);
        setError('Failed to load users.');
      });
  }, [token, navigate]);

  const deleteUser = (id) => {
    fetch(`http://localhost:8000/api/manage-users/${id}/`, {
      method: 'DELETE',
      headers: {
        Authorization: `Bearer ${token}`,
      },
    }).then(() => {
      setUsers(users.filter(user => user.id !== id));
    });
  };

  const handleEditClick = (user) => {
    setEditingUser(user.id);
    setEditedData({ username: user.username, role: user.role });
  };

  const handleEditChange = (e) => {
    setEditedData({ ...editedData, [e.target.name]: e.target.value });
  };

  const updateUser = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`http://localhost:8000/api/manage-users/${editingUser}/`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(editedData),
      });

      if (res.ok) {
        const updated = await res.json();
        setUsers(users.map(user => (user.id === updated.id ? updated : user)));
        setEditingUser(null);
      } else {
        alert('Failed to update user');
      }
    } catch (error) {
      console.error(error);
      alert('Error updating user');
    }
  };

  const handleNewUserChange = (e) => {
    setNewUser({ ...newUser, [e.target.name]: e.target.value });
  };

  const createUser = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch('http://localhost:8000/api/register/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newUser),
      });

      const data = await res.json();

      if (res.ok) {
        alert(`User created with username: ${data.final_username}`);
        setShowForm(false);
        setNewUser({ username: '', email: '', password: '', role: 'student' });
      } else {
        alert(data.error || 'User creation failed.');
      }
    } catch (err) {
      console.error(err);
      alert('Error creating user');
    }
  };

  return (
    <div style={{ padding: '2rem' }}>
      <h2>Moderator Dashboard</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}

      <button onClick={() => setShowForm(!showForm)} style={styles.createBtn}>
        {showForm ? 'Cancel' : 'Create New User'}
      </button>

      {showForm && (
        <form onSubmit={createUser} style={styles.createForm}>
          <input type="text" name="username" placeholder="Username" value={newUser.username} onChange={handleNewUserChange} required />
          <input type="email" name="email" placeholder="Email" value={newUser.email} onChange={handleNewUserChange} required />
          <input type="password" name="password" placeholder="Password" value={newUser.password} onChange={handleNewUserChange} required />
          <select name="role" value={newUser.role} onChange={handleNewUserChange}>
            <option value="student">Student</option>
            <option value="teacher">Teacher</option>
            <option value="moderator">Moderator</option>
          </select>
          <button type="submit" style={styles.submitBtn}>Submit</button>
        </form>
      )}

      <table border="1" cellPadding="10" style={{ width: '100%', marginTop: '2rem' }}>
        <thead>
          <tr>
            <th>ID</th><th>Username</th><th>Role</th><th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map(u => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>
                {editingUser === u.id ? (
                  <input type="text" name="username" value={editedData.username} onChange={handleEditChange} />
                ) : u.username}
              </td>
              <td>
                {editingUser === u.id ? (
                  <select name="role" value={editedData.role} onChange={handleEditChange}>
                    <option value="student">Student</option>
                    <option value="teacher">Teacher</option>
                    <option value="moderator">Moderator</option>
                  </select>
                ) : u.role}
              </td>
              <td>
                {editingUser === u.id ? (
                  <>
                    <button onClick={updateUser} style={styles.updateBtn}>Update</button>
                    <button onClick={() => setEditingUser(null)} style={styles.cancelBtn}>Cancel</button>
                  </>
                ) : (
                  <>
                    <button onClick={() => handleEditClick(u)} style={styles.editBtn}>Edit</button>
                    <button onClick={() => deleteUser(u.id)} style={styles.deleteBtn}>Delete</button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const styles = {
  createBtn: {
    backgroundColor: '#007bff',
    color: 'white',
    padding: '10px 15px',
    border: 'none',
    borderRadius: '4px',
    marginBottom: '1rem',
    cursor: 'pointer'
  },
  createForm: {
    marginBottom: '2rem',
    display: 'flex',
    gap: '10px',
    flexWrap: 'wrap',
    alignItems: 'center'
  },
  submitBtn: {
    backgroundColor: 'green',
    color: '#fff',
    padding: '8px 14px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer'
  },
  editBtn: {
    backgroundColor: '#ffc107',
    color: '#000',
    padding: '6px 10px',
    border: 'none',
    borderRadius: '4px',
    marginRight: '6px',
    cursor: 'pointer'
  },
  deleteBtn: {
    backgroundColor: '#dc3545',
    color: 'white',
    padding: '6px 10px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer'
  },
  updateBtn: {
    backgroundColor: '#17a2b8',
    color: '#fff',
    padding: '6px 10px',
    border: 'none',
    borderRadius: '4px',
    marginRight: '6px',
    cursor: 'pointer'
  },
  cancelBtn: {
    backgroundColor: '#6c757d',
    color: '#fff',
    padding: '6px 10px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer'
  }
};

export default ModeratorDashboard;
